const API_BASE_URL = (process.env.REACT_APP_API_BASE_URL || 'http://localhost:5050/api').replace(/\/$/, '');

function appendQuery(path, query = {}) {
  const params = new URLSearchParams();

  Object.entries(query).forEach(([key, value]) => {
    if (value !== undefined && value !== null && value !== '') {
      params.append(key, String(value));
    }
  });

  const serialized = params.toString();
  return serialized ? `${path}?${serialized}` : path;
}

async function request(path, options = {}) {
  const response = await fetch(`${API_BASE_URL}${path}`, {
    ...options,
    credentials: 'include',
    headers: {
      ...(options.body ? { 'Content-Type': 'application/json' } : {}),
      ...options.headers,
    },
  });

  const payload = await response.json().catch(() => ({
    success: false,
    message: 'Invalid response.',
    code: 'UNEXPECTED_RESPONSE',
  }));

  if (!response.ok) {
    const error = new Error(payload.message || 'Request failed.');
    error.code = payload.code || 'REQUEST_FAILED';
    error.status = response.status;
    error.details = payload.details || null;
    throw error;
  }

  return payload;
}

function jsonRequest(path, method, body) {
  return request(path, {
    method,
    body: JSON.stringify(body),
  });
}

export const adminMentorApi = {
  getAdminDashboard() {
    return request('/admin/dashboard');
  },

  getAdminUsers({ search = '', role = 'ALL', status = 'ALL', skip = 0, take = 20 } = {}) {
    return request(appendQuery('/admin/users', { search, role, status, skip, take }));
  },

  getUserDetail(userId) {
    return request(`/admin/users/${userId}`);
  },

  updateUserStatus(userId, status) {
    return jsonRequest(`/admin/users/${userId}/block`, 'POST', { status });
  },

  getMentors({ search = '', status = 'ALL', skip = 0, take = 20 } = {}) {
    return request(appendQuery('/admin/mentors', { search, status, skip, take }));
  },

  createMentor({ name, email, password }) {
    return jsonRequest('/admin/mentors', 'POST', { name, email, password });
  },

  updateMentor(mentorId, changes) {
    return jsonRequest(`/admin/mentors/${mentorId}`, 'PATCH', changes);
  },

  disableMentor(mentorId) {
    return jsonRequest(`/admin/mentors/${mentorId}`, 'PATCH', { status: 'BLOCKED' });
  },

  assignMentor(mentorId, courseId) {
    return jsonRequest(`/admin/mentors/${mentorId}/assign`, 'POST', { courseId });
  },

  revokeMentorAssignment(assignmentId) {
    return request(`/admin/mentor-assignments/${assignmentId}`, { method: 'DELETE' });
  },

  getAdminReports({ range = '30d', startDate, endDate, granularity } = {}) {
    return request(appendQuery('/admin/reports', { range, startDate, endDate, granularity }));
  },

  getMentorDashboard() {
    return request('/mentor/dashboard');
  },

  getMentorReviewQueue({ courseId = 'ALL', status = 'PENDING' } = {}) {
    return request(appendQuery('/mentor/reviews/queue', { courseId, status }));
  },

  getReviewSubmission(submissionId) {
    return request(`/mentor/submissions/${submissionId}`);
  },

  getSubmissionDetail(submissionId) {
    return request(`/mentor/submissions/${submissionId}`);
  },

  submitReview(submissionId, { result, feedback, score }) {
    return jsonRequest(`/mentor/submissions/${submissionId}/review`, 'POST', {
      result,
      feedback,
      ...(score === undefined || score === '' ? {} : { score }),
    });
  },
};

export const __privateAdminMentorApi = {
  appendQuery,
  request,
};
